+//!
+//! Covers context-aware skill loading based on project type detection,
+//! file patterns, tools, signals, and threshold filtering.
+
+use super::fixture::E2EFixture;
+use ms::error::Result;
+use std::fs;
+
+// =============================================================================
+// SKILL DEFINITIONS WITH CONTEXT TAGS
+// =============================================================================
+
